import axios from "axios";
import { config } from "../../utils/axiosconfig";
import { base_url } from "../../utils/baseUrl";

const getProducts = async () => {
  const response = await axios.get(`${base_url}product/AllProduct`, config);
  return response.data.data || response.data;
};
const getNotApprovedProducts = async (status) => {
  let endpoint = `${base_url}product/NotApproved`; // Default to pending

  // Adjust endpoint based on the status
  if (status === "approved") {
    endpoint = `${base_url}product/Approved`;
  } else if (status === "rejected") {
    endpoint = `${base_url}product/Rejected`;
  }
  //console.log(endpoint)

  try {
    const response = await axios.get(endpoint);
    console.log(response);
    return response.data; // return the data to be used in the component
  } catch (error) {
    console.error("Error fetching products:", error);
    return [];
  }
};

const createProduct = async (product) => {
  const response = await axios.post(`${base_url}product/`, product, config);

  return response.data;
};

const getProduct = async (id) => {
  const response = await axios.get(`${base_url}product/admin/${id}`, config);

  return response.data;
};

const updateProduct = async (product) => {
  // send the entire productData object so backend can handle mapping (colorImagePairs etc.)
  const response = await axios.put(
    `${base_url}product/${product.id}`,
    product.productData,
    config,
  );

  return response.data;
};

const deleteproduct = async (data) => {
  const { productId, userId } = data;

  const requestConfig = {
    ...config,
    data: {
      userId,
    },
  };

  const response = await axios.delete(
    `${base_url}product/${productId}`,
    requestConfig,
  );
  console.log(response.data);

  return response.data;
};

